async (page) => {
  // Check equipment panel - open it to see what's equipped
  const equipInfo = await page.evaluate(() => {
    const player = window.game?.player;
    if (!player) return 'no player';

    // Try different ways to access equipment
    const containers = player.equipment?.containers;
    if (containers) {
      const items = [];
      for (const [key, val] of Object.entries(containers)) {
        if (val && val.key) items.push({ slot: key, key: val.key, name: val.name });
      }
      return items;
    }

    // Try equipment.slots
    const slots = player.equipment?.slots;
    if (slots) return Object.entries(slots).map(([k,v]) => ({slot: k, value: v}));

    return 'no equipment data';
  });

  return JSON.stringify(equipInfo);
}

