async (page) => {
  // Blacksmith is at (199,169), player at (198,169) - distance 1, on_screen true
  // click_y=0 is a bug. From screenshot, Blacksmith is near building to the right.
  // Character center is ~640,360 on a 1280x720 viewport. Blacksmith is 1 tile east.
  // Try clicking at (688, 260) - slightly right and up from character center
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 720, y: 250 });
  await page.waitForTimeout(2000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  // Check if quest popup appeared
  const questVisible = await page.evaluate(() => {
    const q = document.getElementById('quest');
    return q ? window.getComputedStyle(q).display !== 'none' : false;
  });
  return 'Clicked Blacksmith area. Quest visible: ' + questVisible;
}
